CustomFunction.Calculation:
Let
(
[
_table = Quote (
	If ( PatternCount ( table ; "::" ) ;
		Left ( table ; Position ( table ; "::" ; 1 ; 1 ) - 1 ) ;
	// ELSE
		table
	))
];
JSONSetElement ( "{}" ;
[ "table" ; _table ; JSONString ] ;
[ "selects" ; "*" ; JSONString ] ;
[ "selectKeys" ; "*" ; JSONString ] ;
[ "joins" ; "[]" ; JSONRaw ] ;
[ "joinCount" ; 0 ; JSONNumber ] ;
[ "wheres" ; "[]" ; JSONRaw ] ;
[ "whereCount" ; 0 ; JSONNumber ] ;
[ "groupBys" ; "[]" ; JSONRaw ] ;
[ "groupByCount" ; 0 ; JSONNumber ] ;
[ "havings" ; "[]" ; JSONRaw ] ;
[ "havingCount" ; 0 ; JSONNumber ] ;
[ "orderBys" ; "[]" ; JSONRaw ] ;
[ "orderByCount" ; 0 ; JSONNumber ] ;
[ "limit" ; "" ; JSONString ] ;
[ "offset" ; "" ; JSONString ] ;
[ "bindings" ; "[]" ; JSONRaw ] ;
[ "bindingCount" ; 0 ; JSONNumber ]
)
)
